import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    min_distance = np.inf
    next_node = None
    for node in unvisited_nodes:
        if node == destination_node:
            temp_distance = distance_matrix[current_node][node] + distance_matrix[node][destination_node]
        else:
            temp_distance = distance_matrix[current_node][node] + np.sum(distance_matrix[node, unvisited_nodes])
        if temp_distance < min_distance:
            min_distance = temp_distance
            next_node = node
    return next_node
